const Badge = ({ children, color = "green", dark = false }) => {
  const darkColors = {
    green: "bg-emerald-900/50 text-emerald-300 border border-emerald-700/50",
    yellow: "bg-amber-900/50 text-amber-300 border border-amber-700/50",
    red: "bg-red-900/50 text-red-300 border border-red-700/50",
    blue: "bg-blue-900/50 text-blue-300 border border-blue-700/50",
    gray: "bg-stone-800 text-stone-400 border border-stone-700",
  };
  const lightColors = {
    green: "bg-[#e6f2eb] text-[#1a4a2e] border border-[#a3c9b0]",
    yellow: "bg-amber-50 text-amber-800 border border-amber-200",
    red: "bg-red-50 text-red-700 border border-red-200",
    blue: "bg-blue-50 text-blue-700 border border-blue-200",
    gray: "bg-stone-100 text-stone-500 border border-stone-200",
  };
  const colors = dark ? darkColors : lightColors;
  return <span className={`px-2 py-0.5 rounded-full text-xs font-semibold ${colors[color]}`}>{children}</span>;
};

const Card = ({ children, className = "", onClick, style, light = false }) => (
  <div onClick={onClick} style={light ? { background: "white", border: "1px solid #e0d9cf", borderRadius: "1rem", padding: "1.25rem", ...style } : style}
    className={`${light ? "" : "bg-stone-900 border border-stone-800"} rounded-2xl p-5 ${onClick && !light ? "cursor-pointer hover:border-emerald-700/50 transition-all" : onClick ? "cursor-pointer transition-all" : ""} ${className}`}>
    {children}
  </div>
);

const StatCard = ({ label, value, sub, icon, color = "emerald", trend }) => {
  const colors = {
    emerald: "text-emerald-400",
    amber: "text-amber-400",
    blue: "text-blue-400",
    red: "text-red-400",
  };
  return (
    <Card>
      <div className="flex items-start justify-between">
        <div>
          <p className="text-stone-500 text-sm font-medium uppercase tracking-wider">{label}</p>
          <p className={`text-3xl font-black mt-1 ${colors[color]}`}>{value}</p>
          {sub && <p className="text-stone-500 text-xs mt-1">{sub}</p>}
          {trend && <p className="text-emerald-400 text-xs mt-1 flex items-center gap-1"><Icon name="trending" size={12} /> {trend}</p>}
        </div>
        <div className={`w-10 h-10 rounded-xl flex items-center justify-center bg-stone-800 ${colors[color]}`}>
          <Icon name={icon} size={18} color="currentColor" />
        </div>
      </div>
    </Card>
  );
};



