// ── Dynamic activity badge shown in hero ──────────────────────────────────────
// Reflects real schedule: fully generic job types — no customer names exposed
const ACTIVITY_FEED = (() => {
  const today = new Date();
  const dow   = today.getDay(); // 0=Sun … 6=Sat
  const month = today.getMonth(); // 0=Jan … 11=Dec

  // Season helpers
  const isFallSeason   = month >= 8 && month <= 10;  // Sep–Nov
  const isSpring       = month >= 2 && month <= 4;   // Mar–May
  const isSummer       = month >= 5 && month <= 7;   // Jun–Aug

  // Route counts (anonymous)
  const mondayCount   = 4; // Ron, Herb, Deborah, Tara
  const thursdayCount = 2; // Jason, Cory
  const fridayCount   = 3; // Kyle, Roger, Dave (Tara also Fri)

  const mowLabel = (n, route) =>
    `${n} Weekly Lawn${n === 1 ? "" : "s"} — ${route} Route`;

  const feed = [];

  if (dow === 1) { // Monday
    feed.push({ label: mowLabel(mondayCount, "Monday"), sub: "Today · All visits complete ✓", icon: "check" });
    if (isFallSeason)  feed.push({ label: "Fall Clean-Up",           sub: "Leaf removal & bed prep",      icon: "leaf" });
    else if (isSpring) feed.push({ label: "Aeration & Overseeding",  sub: "Spring lawn restoration",      icon: "leaf" });
    else               feed.push({ label: mowLabel(fridayCount, "Friday"), sub: "Last Friday · Complete", icon: "check" });
  } else if (dow === 2) { // Tuesday
    feed.push({ label: mowLabel(mondayCount, "Monday"), sub: "Yesterday · All visits complete ✓", icon: "check" });
    if (isFallSeason)  feed.push({ label: "Mulch Top-Off",           sub: "Bargersville property",        icon: "leaf" });
    else               feed.push({ label: "Landscaping Install",     sub: "Beds + plant material",        icon: "leaf" });
  } else if (dow === 3) { // Wednesday
    feed.push({ label: mowLabel(mondayCount, "Monday"), sub: "2 days ago · Complete ✓",      icon: "check" });
    feed.push({ label: "Free Estimates Open",            sub: "Schedule yours this week",    icon: "sparkle" });
  } else if (dow === 4) { // Thursday
    feed.push({ label: mowLabel(thursdayCount, "Thursday"), sub: "Today · All visits complete ✓", icon: "check" });
    feed.push({ label: mowLabel(mondayCount, "Monday"),     sub: "Monday · Complete ✓",          icon: "check" });
  } else if (dow === 5) { // Friday
    feed.push({ label: mowLabel(fridayCount, "Friday"),   sub: "Today · In progress 🌿",        icon: "leaf" });
    feed.push({ label: mowLabel(thursdayCount, "Thursday"), sub: "Yesterday · Complete ✓",      icon: "check" });
  } else { // Weekend (Sat/Sun)
    feed.push({ label: mowLabel(fridayCount, "Friday"),   sub: "Friday · Route complete ✓",     icon: "check" });
    if (isFallSeason)  feed.push({ label: "Fall Aeration",           sub: "Booked — 3 properties",       icon: "leaf" });
    else if (isSpring) feed.push({ label: "Season Kick-Off Week",    sub: "Spring routes starting Mon",  icon: "sparkle" });
    else               feed.push({ label: "Landscaping Consult",     sub: "Estimate scheduled Monday",   icon: "clipboard" });
  }

  // Seasonal 3rd card
  if (isFallSeason)   feed.push({ label: "Fall Clean-Ups Available", sub: "Limited spots remaining",  icon: "sparkle" });
  else if (isSpring)  feed.push({ label: "Spring Slots Open",        sub: "Book before they fill up", icon: "sparkle" });
  else if (isSummer)  feed.push({ label: "Weekly Mowing — Openings", sub: "2 new client slots left",  icon: "sparkle" });
  else                feed.push({ label: "Free Estimate Available",  sub: "Get your quote today",     icon: "sparkle" });

  return feed;
})();

const HeroActivityBadge = () => {
  const [idx, setIdx] = useState(0);
  const [fade, setFade] = useState(true);

  useEffect(() => {
    const timer = setInterval(() => {
      setFade(false);
      setTimeout(() => {
        setIdx(i => (i + 1) % ACTIVITY_FEED.length);
        setFade(true);
      }, 300);
    }, 3500);
    return () => clearInterval(timer);
  }, []);

  const item = ACTIVITY_FEED[idx];

  return (
    <div
      className="absolute -bottom-4 -left-4 bg-white border border-[#e0d9cf] rounded-2xl shadow-xl shadow-[#1a4a2e]/10 overflow-hidden"
      style={{ minWidth: 244, maxWidth: 284 }}
    >
      {/* header strip */}
      <div className="flex items-center gap-2 px-4 py-2.5 border-b border-[#f0ebe3]" style={{ background: "#faf8f4" }}>
        <div className="w-2 h-2 rounded-full bg-emerald-500" style={{ boxShadow: "0 0 0 3px rgba(16,185,129,0.2)" }} />
        <span className="text-[10px] font-bold uppercase tracking-widest" style={{ color: "#7a9488" }}>Owen's Schedule</span>
      </div>
      {/* body */}
      <div className="p-3" style={{ transition: "opacity 0.3s ease", opacity: fade ? 1 : 0 }}>
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0" style={{ background: "#e8f2ec" }}>
            <Icon name={item.icon} size={16} color="#1a4a2e" />
          </div>
          <div className="min-w-0">
            <div className="text-sm font-bold leading-tight" style={{ color: "#1a1a1a" }}>{item.label}</div>
            <div className="text-xs mt-0.5" style={{ color: "#7a9488" }}>{item.sub}</div>
          </div>
        </div>
        {/* progress dots */}
        <div className="flex gap-1.5 mt-3 justify-center">
          {ACTIVITY_FEED.map((_, i) => (
            <div key={i} className="rounded-full transition-all" style={{
              width: i === idx ? 16 : 6, height: 6,
              background: i === idx ? "#1a4a2e" : "#c8ddd0"
            }} />
          ))}
        </div>
      </div>
    </div>
  );
};

